#[test]
fn usecase_saves_new_user() {
    let mut repo = FakeRepo { exists: false };
    let command = RegisterUserCommand { email: EmailAddress("ada@example.com".to_owned()), display_name: "Ada".to_owned() };
    assert_eq!(register_user(&mut repo, command), Ok(UserId(7)));
}

#[test]
fn usecase_rejects_duplicate_email() {
    let mut repo = FakeRepo { exists: true };
    let command = RegisterUserCommand { email: EmailAddress("ada@example.com".to_owned()), display_name: "Ada".to_owned() };
    assert_eq!(register_user(&mut repo, command), Err(RegisterUserError::DuplicateEmail));
}

